import android.content.Context;
import android.content.SharedPreferences;
import android.os.Bundle;
import android.text.TextUtils;
import android.view.View;
import android.widget.Button;
import android.widget.CheckBox;
import android.widget.EditText;
import android.widget.Toast;
import androidx.appcompat.app.AppCompatActivity;
import androidx.security.crypto.EncryptedSharedPreferences;
import androidx.security.crypto.MasterKey;
import java.io.IOException;
import java.security.GeneralSecurityException;

public class LoginActivity extends AppCompatActivity {

    private EditText emailEditText;
    private EditText passwordEditText;
    private CheckBox rememberMeCheckBox;
    private Button loginButton;
    private SecureCredentialManager credentialManager;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        emailEditText = findViewById(R.id.emailEditText);
        passwordEditText = findViewById(R.id.passwordEditText);
        rememberMeCheckBox = findViewById(R.id.rememberMeCheckBox);
        loginButton = findViewById(R.id.loginButton);

        credentialManager = new SecureCredentialManager(this);

        loadSavedCredentials();

        loginButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                performLogin();
            }
        });
    }

    private void loadSavedCredentials() {
        String savedEmail = credentialManager.getEmail();
        String savedToken = credentialManager.getAuthToken();

        if (!TextUtils.isEmpty(savedEmail) && !TextUtils.isEmpty(savedToken)) {
            emailEditText.setText(savedEmail);
            rememberMeCheckBox.setChecked(true);
            
            if (isTokenValid(savedToken)) {
                navigateToMainActivity();
            }
        }
    }

    private void performLogin() {
        String email = emailEditText.getText().toString().trim();
        String password = passwordEditText.getText().toString().trim();

        if (TextUtils.isEmpty(email) || TextUtils.isEmpty(password)) {
            Toast.makeText(this, "Please enter email and password", Toast.LENGTH_SHORT).show();
            return;
        }

        if (!isValidEmail(email)) {
            Toast.makeText(this, "Please enter a valid email", Toast.LENGTH_SHORT).show();
            return;
        }

        authenticateUser(email, password);
    }

    private void authenticateUser(String email, String password) {
        String authToken = performNetworkAuthentication(email, password);

        if (authToken != null) {
            if (rememberMeCheckBox.isChecked()) {
                credentialManager.saveCredentials(email, authToken);
            } else {
                credentialManager.clearCredentials();
            }

            Toast.makeText(this, "Login successful", Toast.LENGTH_SHORT).show();
            navigateToMainActivity();
        } else {
            Toast.makeText(this, "Login failed", Toast.LENGTH_SHORT).show();
        }
    }

    private String performNetworkAuthentication(String email, String password) {
        return "sample_auth_token_" + System.currentTimeMillis();
    }

    private boolean isTokenValid(String token) {
        return !TextUtils.isEmpty(token);
    }

    private boolean isValidEmail(String email) {
        return android.util.Patterns.EMAIL_ADDRESS.matcher(email).matches();
    }

    private void navigateToMainActivity() {
        finish();
    }

    public void logout() {
        credentialManager.clearCredentials();
    }
}

class SecureCredentialManager {

    private static final String PREFS_FILENAME = "secure_credentials";
    private static final String KEY_EMAIL = "user_email";
    private static final String KEY_AUTH_TOKEN = "auth_token";

    private SharedPreferences sharedPreferences;

    public SecureCredentialManager(Context context) {
        try {
            MasterKey masterKey = new MasterKey.Builder(context)
                    .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
                    .build();

            sharedPreferences = EncryptedSharedPreferences.create(
                    context,
                    PREFS_FILENAME,
                    masterKey,
                    EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
                    EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
            );
        } catch (GeneralSecurityException | IOException e) {
            e.printStackTrace();
            sharedPreferences = context.getSharedPreferences(PREFS_FILENAME, Context.MODE_PRIVATE);
        }
    }

    public void saveCredentials(String email, String authToken) {
        SharedPreferences.Editor editor = sharedPreferences.edit();
        editor.putString(KEY_EMAIL, email);
        editor.putString(KEY_AUTH_TOKEN, authToken);
        editor.apply();
    }

    public String getEmail() {
        return sharedPreferences.getString(KEY_EMAIL, null);
    }

    public String getAuthToken() {
        return sharedPreferences.getString(KEY_AUTH_TOKEN, null);
    }

    public void clearCredentials() {
        SharedPreferences.Editor editor = sharedPreferences.edit();
        editor.remove(KEY_EMAIL);
        editor.remove(KEY_AUTH_TOKEN);
        editor.apply();
    }

    public boolean hasStoredCredentials() {
        return sharedPreferences.contains(KEY_EMAIL) && sharedPreferences.contains(KEY_AUTH_TOKEN);
    }
}